function e(string $v):string{return htmlspecialchars($v,ENT_QUOTES,'UTF-8');}
function status_label(string $s):string{return ['not-opened'=>'Neotvorené','editing'=>'Rozpracované','sent'=>'Odoslané na kontrolu','revision-requested'=>'Vrátené na dopracovanie','approved'=>'Schválené','changed-after-send'=>'Upravené po odoslaní','archived'=>'Archivované'][$s]??$s;}
function app_root_url():string{if(BASE_URL!=='')return BASE_URL;$scheme=(!empty($_SERVER['HTTPS'])&&$_SERVER['HTTPS']!=='off')?'https':'http';$host=$_SERVER['HTTP_HOST']??'localhost';$script=str_replace('\\','/',dirname($_SERVER['SCRIPT_NAME']??'/admin/project.php'));$root=rtrim(dirname($script),'/');return $scheme.'://'.$host.($root==='/'?'':$root);}
$id=preg_replace('/[^a-zA-Z0-9_-]/','',(string)($_GET['id']??''));$file=project_path($id);$project=read_json($file);if(!$id||!$project){http_response_code(404);exit('Projekt sa nenašiel.');}
$root=app_root_url();$editUrl=$root.'/?token='.rawurlencode((string)$project['access']['editToken']);$shareUrl=$root.'/?share='.rawurlencode((string)$project['access']['shareToken']);$adminActor=(string)($_SESSION['admin']??'organizátor');
if($_SERVER['REQUEST_METHOD']==='POST'){
 verify_csrf();$action=(string)($_POST['action']??'');
 if($action==='save-client'){$project['name']=trim((string)($_POST['name']??$project['name']));$project['client']['name']=trim((string)($_POST['clientName']??''));$project['client']['email']=trim((string)($_POST['clientEmail']??''));$project['weddingDate']=(string)($_POST['weddingDate']??'');$project['state']['wedding']['eventName']=$project['name'];$project['state']['wedding']['contactName']=$project['client']['name'];$project['state']['wedding']['email']=$project['client']['email'];$project['state']['wedding']['date']=$project['weddingDate'];activity_add($project,'admin-details',$adminActor,'Organizátor upravil údaje projektu');}
 elseif($action==='send-invite'){$result=send_client_invitation($project,$editUrl);if($result['ok']){$project['meta']['invitationSentAt']=gmdate('c');$project['meta']['invitationSentTo']=$project['client']['email']??'';activity_add($project,'invitation-sent',$adminActor,'Pozvánka bola odoslaná klientovi',['email'=>$project['client']['email']??'']);write_json($file,$project);header('Location:project.php?id='.rawurlencode($id).'&mail=sent');}else header('Location:project.php?id='.rawurlencode($id).'&mail=error&message='.rawurlencode((string)($result['error']??'E-mail sa nepodarilo odoslať.')));exit;}
 elseif($action==='request-revision'||$action==='approve'){$note=trim((string)($_POST['reviewNote']??''));$decision=$action==='approve'?'approved':'revision-requested';$project['status']=$decision;$project['review']=['decision'=>$decision,'note'=>$note,'decidedAt'=>gmdate('c'),'decidedBy'=>$adminActor];$mail=mail_configured()?send_review_decision($project,$decision,$note,$editUrl):['ok'=>false,'error'=>'SMTP nie je nastavené.'];$project['review']['mail']=$mail;activity_add($project,$decision,$adminActor,$decision==='approved'?'Organizátor schválil návrh':'Organizátor vrátil návrh na dopracovanie',['note'=>$note]);$project['meta']['updatedAt']=gmdate('c');write_json($file,$project);header('Location:project.php?id='.rawurlencode($id).'&review='.$decision);exit;}
 elseif($action==='clear-review'){unset($project['review']);$project['status']='editing';activity_add($project,'review-cleared',$adminActor,'Rozhodnutie organizátora bolo zrušené');}
 elseif($action==='enable-share'){$project['access']['shareEnabled']=true;activity_add($project,'share-enabled',$adminActor,'Organizátor zapol zdieľaný odkaz');}
 elseif($action==='disable-share'){$project['access']['shareEnabled']=false;activity_add($project,'share-disabled',$adminActor,'Organizátor vypol zdieľaný odkaz');}
 elseif($action==='regenerate-share'){$project['access']['shareToken']=token();$project['access']['shareEnabled']=true;unset($project['meta']['shareFirstOpenedAt'],$project['meta']['shareLastOpenedAt']);activity_add($project,'share-regenerated',$adminActor,'Organizátor vygeneroval nový zdieľaný odkaz');}
 elseif($action==='regenerate-edit'){$project['access']['editToken']=token();unset($project['meta']['firstOpenedAt'],$project['meta']['lastOpenedAt']);if(($project['status']??'')==='editing')$project['status']='not-opened';activity_add($project,'edit-regenerated',$adminActor,'Organizátor vygeneroval nový editačný odkaz');}
 elseif($action==='archive'){$project['status']='archived';activity_add($project,'archived',$adminActor,'Projekt bol archivovaný');}
 elseif($action==='restore'){$project['status']='editing';activity_add($project,'restored',$adminActor,'Projekt bol obnovený z archívu');}
 elseif($action==='delete'){$confirm=trim((string)($_POST['confirmName']??''));if(!hash_equals((string)$project['name'],$confirm)){header('Location:project.php?id='.rawurlencode($id).'&delete=invalid');exit;}if(is_file($file))unlink($file);$dir=VERSION_DIR.'/'.$id;if(is_dir($dir)){foreach(glob($dir.'/*')?:[] as $v)if(is_file($v))unlink($v);@rmdir($dir);}header('Location:index.php?deleted=1');exit;}
 $project['meta']['updatedAt']=gmdate('c');write_json($file,$project);header('Location:project.php?id='.rawurlencode($id).'&saved=1');exit;
}
$versionDir=VERSION_DIR.'/'.$id;$versions=is_dir($versionDir)?array_reverse(glob($versionDir.'/*.json')?:[]):[];$state=$project['state']??[];$guestCount=count($state['guests']??[]);$tableCount=count(array_filter($state['items']??[],fn($i)=>str_contains((string)($i['type']??''),'table')));$activity=array_reverse($project['activity']??[]);
