<section class="card stats-card"><h2>Stav návrhu</h2><dl><div><dt>Hostia</dt><dd><?=$guestCount?></dd></div><div><dt>Stoly</dt><dd><?=$tableCount?></dd></div><div><dt>Prvýkrát otvorené</dt><dd><?=e((string)($project['meta']['firstOpenedAt']??'—'))?></dd></div><div><dt>Naposledy otvorené</dt><dd><?=e((string)($project['meta']['lastOpenedAt']??'—'))?></dd></div><div><dt>Posledná úprava</dt><dd><?=e((string)($project['meta']['updatedAt']??'—'))?></dd></div><div><dt>Odoslané</dt><dd><?=e((string)($project['meta']['submittedAt']??'—'))?></dd></div></dl></section></div>
