<section class="card"><h2>História aktivít</h2><?php if(!$activity):?><p class="muted">Nové aktivity sa začnú zaznamenávať po nasadení tejto verzie.</p><?php else:?><div class="activity-timeline"><?php foreach($activity as $entry):?><article><span class="activity-dot"></span><div><b><?=e((string)($entry['label']??$entry['type']??'Aktivita'))?></b><small><?=e((string)($entry['actor']??''))?> · <?=e((string)($entry['at']??''))?></small><?php if(!empty($entry['details']['note'])):?><p><?=nl2br(e((string)$entry['details']['note']))?></p><?php endif?></div></article><?php endforeach?></div><?php endif?></section>
